import base64, json, os, pickle
from google.cloud import pubsub_v1 as pubsub

def process(data, context):
    # TODO: implement this function
    print('This message was sent to {} at {}'.format(context.resource, context.timestamp))

    # Decode the data
    decoded = base64.b64decode(data)

    # Load the data into a Python object
    loaded_data = pickle.loads(decoded)

    # Print the data
    print('The message contains: {}'.format(loaded_data))

def main():
    # TODO: implement this function
    project_id = os.getenv("GOOGLE_CLOUD_PROJECT")
    topic_name = 'projects/{}/topics/{}'.format(project_id, 'task-queue')

    subscriber = pubsub.SubscriberClient()
    subscription_path = subscriber.subscription_path(
        project_id, 'task-queue'
    )

    def callback(message):
        print('Received message: {}'.format(message))

        # Process the message
        process(message.data, message)

        # Acknowledge the message
        message.ack()

    subscriber.subscribe(subscription_path, callback=callback)

if __name__ == '__main__':
    main()